const body = $json.body || {};
const headers = $json.headers || {};

const headerToken = String(headers['x-govchat-token'] || headers['X-Govchat-Token'] || '').trim();
const authHeader = String(headers.authorization || headers.Authorization || '').trim();
const bearerToken = authHeader.toLowerCase().startsWith('bearer ')
  ? authHeader.slice(7).trim()
  : '';
const suppliedToken = headerToken || bearerToken;
const expectedToken = String($env.N8N_WEBHOOK_TOKEN || '').trim();

if (!expectedToken) throw new Error('Server misconfiguratie: N8N_WEBHOOK_TOKEN ontbreekt');
if (!suppliedToken || suppliedToken !== expectedToken) throw new Error('Unauthorized webhook token');

function normalizeContent(content) {
  if (typeof content === 'string') return content.trim();
  if (Array.isArray(content)) {
    return content
      .map((part) => {
        if (!part) return '';
        if (typeof part === 'string') return part;
        if (part.type === 'text') return String(part.text || '');
        return '';
      })
      .join(' ')
      .replace(/\s+/g, ' ')
      .trim();
  }
  return '';
}

function buildConversation(messages) {
  if (!Array.isArray(messages) || messages.length === 0) return '';

  const lines = messages
    .map((m) => {
      const role = String(m?.role || 'user').toLowerCase();
      const content = normalizeContent(m?.content);
      if (!content) return '';
      return `[${role}] ${content}`;
    })
    .filter(Boolean);

  if (!lines.length) return '';

  return [
    'Gebruik onderstaande volledige chatgeschiedenis als context:',
    '',
    ...lines,
  ].join('\n');
}

const directText = String(body.text || body.prompt || body.input || '').trim();
const historyText = buildConversation(body.messages);
const inputText = directText || historyText;

if (!inputText) throw new Error('Geen invoertekst gevonden (verwacht text/prompt/input of OpenAI messages)');

return [{
  json: {
    text: inputText,
    requestModel: String(body.model || 'govchat-orchestrator'),
    hasHistory: Boolean(historyText),
  },
}];

